"""
MKT Original Language Commentary — Psalms chapters 41–47
Run: python3 scripts/zc-original-psalms-41-47.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json (MKT text)

Key decisions in this range:
- Ps 41:9: "my close friend who shared my bread" — Jesus cites this in John 13:18 as
  fulfilled in Judas' betrayal. The Hebrew ʾîsh shĕlômî (man of my peace/wholeness)
  + ʾōkêl laḥmî (who eats my bread) — table-fellowship as the covenant bond violated.
- Ps 41:13: The doxology closing Book I of the Psalter — not part of the psalm itself
  but the liturgical seal on the first book.
- Ps 42-43: Almost certainly a single psalm divided in the manuscript tradition — Ps 43
  has no superscription, and both share the identical three-part refrain (42:5, 42:11,
  43:5). Treated as a literary unit in commentary.
- Ps 42:7: "Deep calls to deep" — tĕhôm (the primordial deep of Gen 1:2) used for the
  overwhelming flood-force. The tĕhôm as both terrifying and paradoxically revelatory.
- Ps 44:22: Paul cites this verse in Romans 8:36 to describe believers facing
  persecution — the psalm of innocent suffering becomes the NT's theology of the cross.
- Ps 45:6: ʾĕlōhîm addressed to the king — "Your throne, O God, is forever and ever."
  One of the most theologically contested verses in the OT. Hebrews 1:8 applies it
  directly to Christ. Treatment follows the Hebrews reading as the NT's authoritative
  interpretation, while noting the debate.
- Ps 45:7: "anointed you with the oil of gladness" — cited Heb 1:9 of Christ.
- Ps 46:7/11: YHWH ṣĕbāʾôt + ʿimmānû (with us) — the same components as ʿImmānûʾêl
  (Immanuel), pointing toward Isa 7:14/Matt 1:23.
- Ps 47:5: "God has ascended" — the ascent as the pattern for Christ's ascension.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 41–47 — the closing psalm of Book I with its Judas
#   betrayal verse (Ps 41:9 → John 13:18), the thirst-and-deep lament of Ps 42-43
#   (a single literary unit), the innocent-suffering national lament whose v22 Paul
#   cites in Rom 8:36 (Ps 44), the royal wedding/Messianic psalm where the king is
#   addressed as ʾĕlōhîm (Ps 45 → Heb 1:8-9), the Immanuel-title psalm (Ps 46), and
#   the ascension-and-universal-kingship hymn (Ps 47).
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(41,48)])"

PSALMS = {
  "41": {
    "1": '<p><strong>אַשְׁרֵי מַשְׂכִּיל אֶל-דָּל</strong> (<em>ʾashrê maskîl ʾel-dāl</em>, "Blessed is the one who cares for the vulnerable") — <em>dāl</em>: thin, weak, poor — the one who is diminished (from <em>dālal</em>: to dangle, to be brought low). This is the physically and socially vulnerable person, not the spiritually poor (<em>ʾānî</em>). <em>Maskîl</em> here is not the psalm-type but the verb: "who acts wisely/attentively toward" the vulnerable. The wisdom of the caring person is the reciprocating structure: the LORD will deliver that person in the day of trouble — care given produces care received.</p>',
    "2": '<p><strong>יְהוָה יִשְׁמְרֵהוּ וִיחַיֵּהוּ</strong> (<em>YHWH yishmĕrêhû wîḥayyêhû</em>, "The LORD protects and preserves his life") — <em>shāmar</em>: to keep, to guard; <em>ḥāyāh</em> (piel: to keep alive, to give life). <strong>אַשַּׁר בָּאָרֶץ</strong> (<em>ʾushshar bāʾāreṣ</em>, "he is regarded as blessed in the land") — <em>ʾāshar</em> (pual: to be called/regarded as blessed) — a passive form of the <em>ʾashrê</em> root. The social recognition of blessedness follows from the divine protection. <strong>וְאַל-תִּתְּנֵהוּ בְּנֶפֶשׁ אֹיְבָיו</strong> (<em>wĕʾal-tittĕnêhû bĕnepesh ʾōyĕbāyw</em>, "you will not hand him over to his enemies\' desire") — <em>nepesh</em> (soul/desire): the enemies\' deep appetite for his destruction is thwarted.</p>',
    "3": '<p><strong>יְהוָה יִסְעָדֶנּוּ עַל-עֶרֶשׂ דְּוָי</strong> (<em>YHWH yisʿādennû ʿal-ʿereś dĕwāy</em>, "The LORD supports him on his bed of illness") — <em>sāʿad</em>: to support, to sustain (as a crutch or prop — the word used for bread "sustaining the heart" in Gen 18:5). <em>ʿEreś</em>: a couch, bed; <em>dĕwāy</em>: illness, languishing (from <em>dāwāh</em>: to be faint, sick — the same root as the "sick with love" in Song 2:5). <strong>כָּל-מִשְׁכָּבוֹ הָפַכְתָּ בְחָלְיוֹ</strong> (<em>kol-mishkābô hāpaktā bĕḥolyô</em>, "in his sickness you bring him back to health") — literally "you have turned/transformed all his bed in his illness" — the bed of illness reversed.</p>',
    "4": '<p><strong>אֲנִי-אָמַרְתִּי יְהוָה חָנֵּנִי</strong> (<em>ʾănî-ʾāmartî YHWH ḥonnênî</em>, "As for me, I said, \'LORD, have mercy on me\'") — the shift to the Psalmist\'s own cry: <em>ḥānan</em>: to be gracious, to show unearned favor. <strong>רְפָאָה נַפְשִׁי כִּי-חָטָאתִי לָךְ</strong> (<em>rĕpāʾāh napshî kî-ḥāṭāʾtî lāk</em>, "heal my soul, for I have sinned against you") — <em>rāpāʾ</em>: to heal; <em>nāpesh</em>: the whole animated self. The confession that the sickness may be connected to sin — not as a theological claim that all sickness is punishment, but as the Psalmist\'s personal acknowledgment of a possible link. The prayer is for healing of the <em>nāpesh</em> (the inner person), not merely the body.</p>',
    "5": '<p><strong>אוֹיְבַי יֹאמְרוּ רַע לִי</strong> (<em>ʾôyĕbay yōʾmĕrû raʿ lî</em>, "My enemies speak wickedly against me") — literally "speak evil of me/to me." <strong>מָתַי יָמוּת וְאָבַד שְׁמוֹ</strong> (<em>mātay yāmût wĕʾābad shĕmô</em>, "When will he die and his name vanish?") — <em>māwet</em>: death; <em>ʾābad</em>: to perish, to be destroyed. The enemies\' desire: not merely his death but the obliteration of his <em>shēm</em> (name/reputation) — the erasure of his social existence. In the ancient world, the continuity of one\'s name was the nearest equivalent to immortality.</p>',
    "6": '<p><strong>וְאִם-בָּא לִרְאוֹת שָׁוְא יְדַבֵּר</strong> (<em>wĕʾim-bāʾ lirʾôt shāwľ yĕdabbêr</em>, "When one of them comes to visit me, he mouths empty words") — <em>shāwľ</em>: emptiness, worthlessness, vanity — the visit is a social performance concealing hostile intelligence-gathering. <strong>לִבּוֹ יִקְבָּץ-אָוֶן לוֹ</strong> (<em>libbô yiqbaṣ-ʾāwen lô</em>, "while inwardly filing away material against me") — <em>qābaṣ</em>: to gather, to collect; <em>ʾāwen</em>: trouble, iniquity, harmful intention. The heart as the storage chamber for accumulated ammunition against the sick person.</p>',
    "7": '<p><strong>יַחַד עָלַי יִתְלַחֲשׁוּ כָּל-שֹׂנְאָי</strong> (<em>yaḥad ʿālay yitlaḥăshû kol-śōnĕʾāy</em>, "All who hate me whisper together against me") — <em>lāḥash</em>: to whisper, to mutter (originally of the snake\'s hiss — the same root used for the whisperer/serpent of Gen 3:1). <em>Yaḥad</em>: together, as a unified conspiracy. <strong>עָלַי יַחְשְׁבוּ רָעָה לִי</strong> (<em>ʿālay yaḥshĕbû rāʿāh lî</em>, "they are plotting disaster for me") — <em>ḥāshab</em>: to think, to devise, to calculate (the accounting word — planning evil as deliberate design).</p>',
    "8": '<p><strong>דְּבַר-בְּלִיַּעַל יָצוּק בּוֹ</strong> (<em>dĕbar-bĕliyaʿal yāṣûq bô</em>, "Something incurable has seized him") — <em>bĕliyaʿal</em>: the chaos/worthlessness force (as in Ps 18:4 — Belial). The phrase "a word/thing of Belial is poured into him" — the illness as the hostile force of chaotic destruction fastened on him. <strong>וַאֲשֶׁר שָׁכַב לֹא-יוֹסִיף לָקוּם</strong> (<em>waʾăsher shākab lōʾ-yôsîp lāqûm</em>, "he will never get up from where he is lying") — the enemies\' confident prediction: this is terminal. The language of the lying-down of death.</p>',
    "9": '<p><strong>גַּם-אִישׁ שְׁלוֹמִי אֲשֶׁר-בָּטַחְתִּי בוֹ</strong> (<em>gam-ʾîsh shĕlômî ʾăsher-bāṭaḥtî bô</em>, "Even my closest friend, whom I trusted") — <em>ʾîsh shĕlômî</em>: "man of my peace/wholeness" — the one with whom one shares <em>shālôm</em> (covenant wholeness). <em>Bāṭaḥ</em>: to trust, to lean on. <strong>אוֹכֵל לַחְמִי הִגְדִּיל עָלַי עָקֵב</strong> (<em>ʾōkêl laḥmî higdîl ʿālay ʿāqêb</em>, "who shared my bread, has turned against me") — <em>ʾōkêl laḥmî</em>: "one who eats my bread" — table-fellowship as the covenant bond; bread-sharing was the sign of covenant relationship (Gen 31:54; Exod 18:12). <em>ʿĀqêb</em>: heel — "lifted up the heel against me." Jesus applies this verse to Judas in John 13:18 ("the one who eats my bread has turned against me"), making the betrayal the fulfillment of this pattern.</p>',
    "10": '<p><strong>וְאַתָּה יְהוָה חָנֵּנִי וַהֲקִימֵנִי</strong> (<em>wĕʾattāh YHWH ḥonnênî wahăqîmênî</em>, "But you, LORD, have mercy on me and restore me") — the turn from the enemies\' confident prediction (he will never rise) to the prayer for rising. <em>Qûm</em> (hiphil: to cause to rise, to set upright): the counterword to the lying-down of v8. <strong>וַאֲשַׁלְּמָה-לָּהֶם</strong> (<em>waʾăshallĕmāh-lāhem</em>, "so that I may give them what they deserve") — <em>shālam</em> (piel: to repay, to complete — the same root as <em>shālôm</em>). The imprecation: repayment in full to those who violated the covenant of peace.</p>',
    "11": '<p><strong>בְּזֹאת יָדַעְתִּי כִּי-חָפַצְתָּ בִּי</strong> (<em>bĕzōʾt yādaʿtî kî-ḥāpaṣtā bî</em>, "By this I know that you are pleased with me") — <em>ḥāpēṣ</em>: to delight in, to take pleasure in (the covenant-pleasure word of Ps 18:19; 5:4). The sign of divine pleasure: <strong>כִּי לֹא-יָרִיעַ אֹיְבִי עָלָי</strong> (<em>kî lōʾ-yārîaʿ ʾōyĕbî ʿālay</em>, "my enemy has not triumphed over me") — <em>rûaʿ</em> (hiphil: to shout in triumph, to raise the victory cry). The enemy\'s silence is read as the sign of God\'s favorable attention.</p>',
    "12": '<p><strong>וַאֲנִי בְּתֻמִּי תָּמַכְתָּ בִּי</strong> (<em>waʾănî bĕtummî tāmaktā bî</em>, "As for me, you hold me up in my integrity") — <em>tōm</em>: integrity, completeness, blamelessness (from <em>tāmam</em>: to be complete — the root of <em>tāmîm</em>). <em>Tāmak</em>: to hold, to support. <strong>וַתַּצִּיבֵנִי לְפָנֶיךָ לְעוֹלָם</strong> (<em>wattaṣṣîbênî lĕpānêkā lĕʿôlām</em>, "and place me before your face forever") — <em>yāṣab</em> (hiphil: to set upright, to station) — permanently positioned before the divine face, the place of covenant nearness and honor.</p>',
    "13": '<p><strong>בָּרוּךְ יְהוָה אֱלֹהֵי יִשְׂרָאֵל מֵהָעוֹלָם וְעַד הָעוֹלָם</strong> (<em>bārûk YHWH ʾĕlōhê yisrāʾêl mêhāʿôlām wĕʿad hāʿôlām</em>, "Blessed be the LORD, the God of Israel, from everlasting to everlasting") — this verse is the closing doxology of Book I of the Psalter (Ps 1-41), not part of Psalm 41 itself. Each of the five books of the Psalter closes with a similar doxological formula (see also Ps 72:18-19; 89:52; 106:48; 150:6). <em>Mêhāʿôlām wĕʿad hāʿôlām</em>: "from the age/hidden-one to the age/hidden-one" — the vast expanse of time in both directions, enclosing all temporal existence. <strong>אָמֵן וְאָמֵן</strong> (<em>ʾāmên wĕʾāmên</em>, "Amen and Amen") — the double liturgical affirmation: <em>ʾāmên</em> (truly so, let it stand firm — from <em>ʾāman</em>: to be firm, reliable, faithful). The congregation\'s ratification of the doxology.</p>',
  },
  "42": {
    "1": '<p><strong>כְּאַיָּל תַּעֲרֹג עַל-אֲפִיקֵי-מָיִם</strong> (<em>kĕʾayyāl taʿărōg ʿal-ʾăpîqê-māyim</em>, "As a deer longs for flowing streams") — <em>ʾayyāl</em>: a male deer/stag (the feminine <em>ʾayyālāh</em> also possible; some texts have the feminine panting; both genders used). <em>ʿĀrag</em>: to long for, to pant (possibly an onomatopoeia of the panting breath; used only here and Joel 1:20 of animals). <em>ʾĂpîqîm</em>: river-channels, watercourses (the irrigation channels of Ps 1:3). <strong>כֵּן נַפְשִׁי תַעֲרֹג אֵלֶיךָ אֱלֹהִים</strong> (<em>kên napshî taʿărōg ʾêlêkā ʾĕlōhîm</em>, "so my soul longs for you, O God") — the simile equates <em>nāpesh</em> (the animating self, the whole person) with the thirsting deer. The longing is whole-person, not merely intellectual or emotional.</p>',
    "2": '<p><strong>צָמְאָה נַפְשִׁי לֵאלֹהִים לְאֵל חָי</strong> (<em>ṣāmĕʾāh napshî lêʾlōhîm lĕʾêl ḥāy</em>, "My soul thirsts for God, for the living God") — <em>ṣāmēʾ</em>: to thirst (the physical, urgent thirst of dehydration). <em>ʾÊl ḥāy</em>: the living God — the one who is characterized by life (<em>ḥayyîm</em>), in contrast to the idols who are dead (<em>mêtîm</em>). John 7:37-38 echoes this thirst-language: "If anyone is thirsty, let him come to me and drink." <strong>מָתַי אָבוֹא וְאֵרָאֶה פְּנֵי אֱלֹהִים</strong> (<em>mātay ʾābôʾ wĕʾêrāʾeh pĕnê ʾĕlōhîm</em>, "When will I come and stand in God\'s presence?") — literally "see the face of God" — the pilgrim desire to appear before God in the sanctuary (Exod 23:17). The exile from the temple is the exile from the face of God.</p>',
    "3": '<p><strong>הָיְתָה-לִּי דִמְעָתִי לֶחֶם יוֹמָם וָלָיְלָה</strong> (<em>hāyĕtāh-llî dimʿātî leḥem yômām wālaylāh</em>, "My tears have been my food day and night") — <em>dimʿāh</em>: tears (tear-drops); <em>leḥem</em>: bread, food. The tears replace the bread — grief replaces nourishment. The inversion of the hunger-satisfaction cycle: instead of eating to live, one weeps without end. <strong>בֶּאֱמֹר אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ</strong> (<em>beʾĕmōr ʾêlay kol-hayyôm ʾayyêh ʾĕlōhêkā</em>, "while people keep saying to me all day long, \'Where is your God?\'") — the repeated taunt (<em>ʾayyêh</em>: where?): the enemies interpret the Psalmist\'s suffering as proof of divine absence or divine abandonment. This is the same taunt in Ps 79:10 and Ps 115:2.</p>',
    "4": '<p><strong>אֵלֶּה אֶזְכְּרָה וְאֶשְׁפְּכָה עָלַי נַפְשִׁי</strong> (<em>ʾêlleh ʾezkĕrāh wĕʾeshpĕkāh ʿālay napshî</em>, "These things I remember as I pour out my soul") — <em>shāpak</em>: to pour out (as water is poured from a vessel). The <em>nāpesh</em> poured out — the whole self emptied in grief (as in Ps 62:8: "pour out your hearts to him"; and Lam 2:19). <strong>כִּי אֶעֱבֹר בַּסָּךְ</strong> (<em>kî ʾeʿĕbōr bassāk</em>, "how I used to walk with the crowd, leading them in procession") — <em>sāk</em>: the sheltering canopy of the festival crowd, the festal procession with its protective multitude. The memory of leading the pilgrimage procession to the house of God, now inaccessible.</p>',
    "5": '<p><strong>מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי</strong> (<em>māh-tishtôḥăḥî napshî</em>, "Why are you downcast, O my soul?") — the refrain (also v11; 43:5): the Psalmist addresses himself in the second person — a kind of inner dialogue or self-counsel. <em>Shāḥāh</em> (hithpolel: to bow down, to be bent over, to be downcast) — the soul bowed under the weight of grief. <strong>וּמַה-תֶּהֱמִי עָלָי</strong> (<em>ûmāh-tehĕmî ʿālay</em>, "Why so disturbed within me?") — <em>hāmāh</em>: to roar, to make a loud sound, to be in tumult — the inner noise of distress. <strong>יַחֲלִי לֵאלֹהִים</strong> (<em>yaḥălî lêʾlōhîm</em>, "Put your hope in God") — <em>yāḥal</em>: to wait with expectation. The self-counsel: direct the tumult toward God rather than turning inward.</p>',
    "6": '<p><strong>עָלַי נַפְשִׁי תִשְׁתּוֹחָח</strong> (<em>ʿālay napshî tishtôḥāḥ</em>, "My soul is cast down within me") — resuming the self-address: the soul that was told to hope (v5) is still downcast. <strong>עַל-כֵּן אֶזְכָּרְךָ מֵאֶרֶץ יַרְדֵּן וְחֶרְמוֹנִים</strong> (<em>ʿal-kên ʾezkārĕkā mêʾereṣ yardên wĕḥermônîm</em>, "therefore I remember you from the land of Jordan, the heights of Hermon") — the physical distance from Jerusalem specified: the Jordan region and Hermon (the north) — far from the temple, recalling God from a distance. Memory as the substitute for physical presence when access is denied.</p>',
    "7": '<p><strong>תְּהוֹם-אֶל-תְּהוֹם קוֹרֵא</strong> (<em>tĕhôm-ʾel-tĕhôm qôrêʾ</em>, "Deep calls to deep") — <em>tĕhôm</em>: the primordial deep (Gen 1:2: "the Spirit of God was hovering over the face of the <em>tĕhôm</em>"). The deep calls to the deep — disaster summons disaster in a chain reaction of overwhelming force. <strong>לְקוֹל צִנּוֹרֶיךָ</strong> (<em>lĕqôl ṣinnôrêkā</em>, "at the roar of your waterfalls") — <em>ṣinnôr</em>: a waterspout, a channel (possibly the torrential channels through which floodwaters pour). <strong>כָּל-מִשְׁבָּרֶיךָ וְגַלֶּיךָ עָלַי עָבָרוּ</strong> (<em>kol-mishbārêkā wĕgallêkā ʿālay ʿābārû</em>, "all your waves and breakers have rolled over me") — <em>mishbār</em>: a breaker (where waves break on rocks); <em>gal</em>: a wave. Both owned by "you" — these are God\'s waves, not random chaos. The same language Jonah uses in his prayer from the fish\'s belly (Jon 2:3).</p>',
    "8": '<p><strong>יוֹמָם יְצַוֶּה יְהוָה חַסְדּוֹ</strong> (<em>yômām yĕṣawweh YHWH ḥasdô</em>, "By day the LORD directs his steadfast love") — the counter-movement within the flood: while the depths overwhelm, by day the LORD commands (<em>ṣāwāh</em>: to command, to issue an order) his <em>ḥesed</em> (covenant loyalty). <strong>וּבַלַּיְלָה שִׁירֹה עִמִּי</strong> (<em>ûbalaylāh shîrô ʿimmî</em>, "at night his song is with me") — even through the night of suffering, the divine song (<em>shîr</em>) accompanies. <strong>תְּפִלָּה לְאֵל חַיַּי</strong> (<em>tĕpillāh lĕʾêl ḥayyāy</em>, "a prayer to the God of my life") — <em>ʾêl ḥayyāy</em>: the God of my life/lives — the same epithet as v2 (<em>ʾêl ḥāy</em>), now possessively attached: "my" life-God.</p>',
    "9": '<p><strong>אוֹמְרָה לְאֵל סַלְעִי לָמָה שְׁכַחְתָּנִי</strong> (<em>ʾômĕrāh lĕʾêl salʿî lāmāh shĕkahttānî</em>, "I say to God my rock, \'Why have you forgotten me?\'") — <em>selaʿ</em>: the rock/cliff-face (as in Ps 18:2; 31:3). <strong>לָמָּה-קֹדֵר אֵלֵךְ</strong> (<em>lāmmāh-qōdêr ʾêlêk</em>, "Why do I walk in mourning?") — <em>qādar</em>: to be dark, to mourn (from the darkened appearance of the mourner\'s face). <strong>בְּלַחַץ אוֹיֵב</strong> (<em>bĕlaḥaṣ ʾôyêb</em>, "under the oppression of the enemy") — <em>laḥaṣ</em>: pressure, oppression (from <em>lāḥaṣ</em>: to press, to squeeze). The enemy as a force that presses and constricts.</p>',
    "10": '<p><strong>בְּרֶצַח בְּעַצְמוֹתַי חֵרְפוּנִי</strong> (<em>bĕreṣaḥ bĕʿaṣmôtay ḥêrĕpûnî</em>, "As if a sword were cutting through my bones, my enemies taunt me") — <em>reṣaḥ</em>: a killing blow, a shattering stroke (from <em>rāṣaḥ</em>: to murder, to slay). The taunt is experienced as a physical blow to the skeleton. <em>Ḥārap</em>: to taunt, to reproach, to shame (the same word as <em>ḥerpāh</em> in Ps 31:11). <strong>בְּאָמְרָם אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ</strong> — the same taunt as v3: "Where is your God?" — the repetition showing the relentless nature of the social assault.</p>',
    "11": '<p>The refrain for the second time: <strong>מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי</strong> — "Why are you downcast, O my soul?" The repetition of the identical refrain (also in 43:5) argues strongly that Psalms 42 and 43 are one literary unit. The refrain is not despair — it is the Psalmist\'s deliberate self-interruption, refusing to let grief have the final word: <strong>יַחֲלִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ יְשׁוּעֹת פָּנָיו</strong> (<em>yaḥălî lêʾlōhîm kî-ʿôd ʾôdennû yĕshûʿōt pānāyw</em>, "Put your hope in God, for I will yet praise him — my Savior and my God") — <em>yĕshûʿōt pānāyw</em>: "salvations of his face" — the face as the source of saving presence.</p>',
  },
  "43": {
    "1": '<p>Psalm 43 has no superscription — unlike every other psalm in Book II — confirming that Psalms 42-43 form a single composition. <strong>שָׁפְטֵנִי אֱלֹהִים וְרִיבָה רִיבִי</strong> (<em>shāpĕṭênî ʾĕlōhîm wĕrîbāh rîbî</em>, "Vindicate me, O God, and plead my cause") — <em>shāpaṭ</em>: to judge, to vindicate (in a legal dispute, the judge who decides in one\'s favor vindicates); <em>rîb</em>: a legal dispute, a lawsuit. <em>Rîbāh rîbî</em>: "plead my dispute/case" — the Psalmist brings God to court as his advocate against the hostile nation. <strong>מֵאִישׁ-מִרְמָה וְעַוְלָה פַלְּטֵנִי</strong> (<em>mêʾîsh-mirmāh wĕʿawlāh pallĕṭênî</em>, "from the deceitful and unjust man deliver me") — <em>mirmāh</em>: deceit, treachery; <em>ʿawlāh</em>: injustice, perversity — the twin character of the enemy.</p>',
    "2": '<p><strong>כִּי-אַתָּה אֱלֹהֵי מָעוּזִּי</strong> (<em>kî-ʾattāh ʾĕlōhê māʿûzzî</em>, "For you are the God who is my stronghold") — <em>māʿôz</em>: fortress, stronghold (as in Ps 28:8). <strong>לָמָה זְנַחְתָּנִי</strong> (<em>lāmāh zĕnaḥtānî</em>, "why have you rejected me?") — <em>zānaḥ</em>: to reject, to cast away (the word for covenant rejection — Jer 7:29; Ps 44:9). The paradox: the God who is the stronghold has also apparently rejected. <strong>לָמָּה-קֹדֵר אֶתְהַלֵּךְ</strong> (<em>lāmmāh-qōdêr ʾethalêk</em>, "Why do I go about mourning?") — the same <em>qādar</em> (to be dark, to go about in mourning) as Ps 42:9 — the two psalms share vocabulary as well as refrain.</p>',
    "3": '<p><strong>שְׁלַח-אוֹרְךָ וַאֲמִתְּךָ</strong> (<em>shĕlaḥ-ʾôrĕkā waʾămittĕkā</em>, "Send out your light and your truth") — the two divine guides personified: <em>ʾôr</em> (light) and <em>ʾĕmet</em> (truth/faithfulness) sent like advance envoys to lead the Psalmist back to God\'s holy mountain. Light and truth as the conditions for the journey to divine presence. <strong>יְנַחוּנִי</strong> (<em>yĕnaḥûnî</em>, "let them lead me") — <em>nāḥāh</em>: to guide, to lead (the shepherd-guide verb of Ps 31:3). The two divine attributes personified as guides — prefiguring the Johannine language of the Spirit of truth who leads into all truth (John 16:13).</p>',
    "4": '<p><strong>וְאָבוֹאָה אֶל-מִזְבַּח אֱלֹהִים</strong> (<em>wĕʾābôʾāh ʾel-mizbah ʾĕlōhîm</em>, "Then I will approach the altar of God") — the <em>mizbêaḥ</em> (altar): the place of sacrifice and access, the point where the human and divine meet. <strong>אֶל-אֵל שִׂמְחַת גִּילִי</strong> (<em>ʾel-ʾêl śimḥat gîlî</em>, "to God who is my greatest joy") — <em>śimḥat gîlî</em>: "the joy of my exultation/dancing" — <em>gîl</em> (the physical, dancing joy) combined with <em>śimḥāh</em> (rejoicing). God himself is the content of the joy, not merely its source. <strong>וְאוֹדְךָ בְכִנּוֹר אֱלֹהִים אֱלֹהָי</strong> (<em>wĕʾôdĕkā bĕkinnôr ʾĕlōhîm ʾĕlōhāy</em>, "I will praise you with the harp, O God my God") — the vow of praise with the <em>kinnôr</em> (lyre/harp — David\'s instrument) once the pilgrimage is restored.</p>',
    "5": '<p>The third and final occurrence of the refrain: <strong>מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי</strong> — "Why are you downcast, O my soul?" — closing the literary unit of Psalms 42-43 with the identical words of 42:5 and 42:11. The three-part refrain structures the whole composition as a progressive self-counsel: each recurrence after a descent into lament is the act of self-interruption — the Psalmist refuses to end on despair. The final refrain has the same hope-turn as the previous two: <strong>יַחֲלִי לֵאלֹהִים</strong> (<em>yaḥălî lêʾlōhîm</em>, "Put your hope in God") — <em>yāḥal</em>: to wait with expectation. The last word is not despair but directed hope.</p>',
  },
  "44": {
    "1": '<p>Psalm 44 is the first of the communal laments — the "we" of the nation rather than the "I" of the individual. <strong>אֱלֹהִים בְּאָזְנֵינוּ שָׁמַעְנוּ</strong> (<em>ʾĕlōhîm bĕʾāznênû shāmaʿnû</em>, "O God, we have heard with our own ears") — <em>bĕʾāznênû</em>: "with our ears" — the auditory reception of tradition. <strong>אֲבוֹתֵינוּ סִפְּרוּ-לָנוּ</strong> (<em>ʾăbôtênû sippĕrû-lānû</em>, "our ancestors have told us what you accomplished") — <em>sāpar</em> (piel: to recount, to narrate — the word behind <em>mizmôr</em> and the ongoing declaration of Ps 19:1). The historical tradition as oral narrative passed from generation to generation.</p>',
    "2": '<p><strong>אַתָּה יָדְךָ גּוֹיִם הוֹרַשְׁתָּ</strong> (<em>ʾattāh yādĕkā gôyim hôrashtā</em>, "With your own hand you drove out the nations") — <em>yārash</em> (hiphil: to dispossess, to drive out): the Conquest vocabulary. <strong>וַתִּטָּעֵם</strong> (<em>wattiṭṭāʿêm</em>, "and planted our ancestors") — <em>nāṭaʿ</em>: to plant (as trees are planted) — the ancestors as a planted community in their land. <strong>תָּרַע לְאֻמִּים וַתְּשַׁלְּחֵם</strong> (<em>tārǎʿ lĕʾummîm wattĕshallĕḥêm</em>, "you crushed the peoples and expelled them") — the two-stage action: crush (<em>rāʿaʿ</em>: to shatter, to break in pieces) then expel (<em>shālaḥ</em>: to send away, to release).</p>',
    "3": '<p><strong>כִּי לֹא בְחַרְבָּם יָרְשׁוּ אָרֶץ</strong> (<em>kî lōʾ bĕḥarbām yārĕshû ʾāreṣ</em>, "For they did not win the land by their own sword") — the theological interpretation of the Conquest: not by their own military prowess. <strong>וּזְרוֹעָם לֹא-הוֹשִׁיעָה לָּמוֹ</strong> (<em>ûzĕrôʿām lōʾ-hôshîʿāh llāmô</em>, "and their own arm did not deliver them") — <em>zĕrôaʿ</em>: arm (the symbol of human strength and military power). <strong>כִּי-יְמִינְךָ וּזְרוֹעֲךָ</strong> (<em>kî-yĕmînĕkā ûzĕrôʿĕkā</em>, "it was your right hand and your arm") — the same word <em>zĕrôaʿ</em> (arm) now applied to God: the divine arm accomplished what the human arm could not. <strong>וְאוֹר פָּנֶיךָ כִּי רְצִיתָם</strong> (<em>wĕʾôr pānêkā kî rĕṣîtām</em>, "and the light of your face, because you were favorable toward them") — <em>rāṣāh</em>: to be favorable, to take pleasure in — the divine pleasure as the ultimate reason for the conquest.</p>',
    "4": '<p><strong>אַתָּה-הוּא מַלְכִּי אֱלֹהִים</strong> (<em>ʾattāh-hûʾ malkî ʾĕlōhîm</em>, "You are my King, O God") — the shift from the communal recitation to the first-person singular: the individual or royal voice within the communal psalm. <strong>צַוֵּה יְשׁוּעוֹת יַעֲקֹב</strong> (<em>ṣawwêh yĕshûʿôt yaʿăqōb</em>, "decree victories for Jacob") — <em>ṣāwāh</em> (piel: to command, to decree): the divine word of command that actualizes salvation. <em>Yĕshûʿôt</em> (plural: salvations — multiple acts of rescue).</p>',
    "5": '<p><strong>בְּךָ צָרֵינוּ נְנַגֵּחַ</strong> (<em>bĕkā ṣārênû nĕnaggêaḥ</em>, "Through you we push back our enemies") — <em>nāgaḥ</em>: to gore, to push (as a bull uses its horns). <strong>בְּשִׁמְךָ נָבוּס קָמֵינוּ</strong> (<em>bĕshimkā nābûs qāmênû</em>, "in your name we trample those who rise against us") — <em>bûs</em>: to trample with the feet. Both verbs are animal-strength images — the horn-push and the hoof-trample — applied to the community\'s combat, but "through you" and "in your name" locate the power in the divine name, not in the community\'s own strength.</p>',
    "6": '<p><strong>כִּי לֹא בְקַשְׁתִּי אֶבְטָח</strong> (<em>kî lōʾ bĕqashtî ʾebṭāḥ</em>, "For I do not trust in my bow") — <em>qeshet</em>: a bow — the primary long-range weapon. <em>Bāṭaḥ</em>: to trust, to lean on (the recurring trust-verb). The explicit renunciation of military self-reliance — the bow as the symbol of personal martial capacity.</p>',
    "7": '<p><strong>כִּי הוֹשַׁעְתָּנוּ מִצָּרֵינוּ</strong> (<em>kî hôshaʿtānû miṣṣārênû</em>, "But you have saved us from our enemies") — <em>yāshaʿ</em> (hiphil: to cause to be saved, to rescue): God as the active saver — the hiphil causative shows God bringing salvation into being, not merely permitting it. <strong>וּמְשַׂנְאֵינוּ הֱבִישׁוֹתָ</strong> (<em>ûmĕśanĕʾênû hĕbîshôtā</em>, "and disgraced those who hate us") — <em>bûsh</em> (hiphil: to cause to be ashamed): God shaming the enemies — the reversal of the taunt.</p>',
    "8": '<p><strong>בֵּאלֹהִים הִלַּלְנוּ כָל-הַיּוֹם</strong> (<em>bêʾlōhîm hillalnû kol-hayyôm</em>, "In God we have boasted all day long") — <em>hālal</em> (piel: to praise, to boast about — the same root as <em>hallĕlûyāh</em>). The community\'s continuous boasting is entirely "in God" (<em>bêʾlōhîm</em>) — not in their own history or identity. <em>Selāh</em> marks the transition to the lament that follows.</p>',
    "9": '<p><strong>אַף-זָנַחְתָּ וַתַּכְלִימֵנוּ</strong> (<em>ʾap-zānaḥtā wattaklîmênû</em>, "But you have cast us off and brought us to disgrace") — the shocking reversal: the same God who saved (v7) has now rejected (<em>zānaḥ</em>: to cast away — the covenant-rejection word). <em>Kālam</em> (hiphil: to bring to shame, to disgrace): public humiliation. <strong>וְלֹא-תֵצֵא בְּצִבְאֹתֵינוּ</strong> (<em>wĕlōʾ-têṣêʾ bĕṣibʾôtênû</em>, "and have not gone out with our armies") — the divine warrior who fought with Israel (v3) is no longer accompanying the armies. The divine desertion of the military host.</p>',
    "10": '<p><strong>תְּשִׁיבֵנוּ אָחוֹר מִנִּי-צָר</strong> (<em>tĕshîbênû ʾāḥôr minnî-ṣār</em>, "You made us retreat before the enemy") — <em>shûb</em> (hiphil: to cause to turn back): not voluntary retreat but forced turning. <em>Ṣār</em>: the adversary (the same <em>ṣar</em> root as distress — the enemy as the tightening force). <strong>וּמְשַׂנְאֵינוּ שָׁסוּ לָמוֹ</strong> (<em>ûmĕśanĕʾênû shāsû lāmô</em>, "and our enemies plundered us") — <em>shāsāh</em>: to plunder, to despoil — taking what belongs to the defeated.</p>',
    "11": '<p><strong>תִּתְּנֵנוּ כְּצֹאן מַאֲכָל</strong> (<em>tittĕnênû kĕṣōʾn maʾăkāl</em>, "You handed us over like sheep for slaughter") — <em>ṣōʾn</em>: the flock; <em>maʾăkāl</em>: food — the sheep as food for those who devour them. The passive submission of the defenseless flock. This verse anticipates Ps 44:22, which Paul quotes directly. <strong>וּבַגּוֹיִם זֵרִיתָנוּ</strong> (<em>ûbaggôyim zêrîtānû</em>, "and scattered us among the nations") — <em>zārāh</em>: to scatter, to winnow (as grain is scattered to the winds): the diaspora-scattering as divine action.</p>',
    "12": '<p><strong>תִּמְכֹּר-עַמְּךָ בְלֹא-הוֹן</strong> (<em>timkōr-ʿammĕkā bĕlōʾ-hôn</em>, "You sold your people for a pittance") — <em>mākar</em>: to sell — the commercial vocabulary applied shockingly to God\'s people. <em>Hôn</em>: wealth, something of value. "Without wealth" — sold for nothing, the sale making no profit. The degradation is total: not even a fair price for the defeat.</p>',
    "13": '<p><strong>תְּשִׂימֵנוּ חֶרְפָּה לִשְׁכֵנֵינוּ</strong> (<em>tĕśîmênû ḥerpāh lishkênênû</em>, "You have made us the object of mockery to our neighbors") — <em>ḥerpāh</em>: reproach, scorn (the same word as Ps 31:11 — the individual\'s shame now the community\'s). <strong>לַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ</strong> (<em>laʿag wāqeles lisĕbîbôtênû</em>, "a laughingstock and a source of scorn to those around us") — <em>laʿag</em>: mockery, derision; <em>qeles</em>: scorn, ridicule (only here and Ezek 36:4 — rare word). The community encircled by the laughter of their neighbors.</p>',
    "14": '<p><strong>תְּשִׂימֵנוּ מָשָׁל בַּגּוֹיִם</strong> (<em>tĕśîmênû māshāl baggôyim</em>, "You have made us a byword among the nations") — <em>māshāl</em>: a proverb, a byword (to "become a <em>māshāl</em>" means to be a cautionary tale — Deut 28:37 threatens this as a covenant curse). <strong>מְנוֹד-רֹאשׁ בַּלְאֻמִּים</strong> (<em>mĕnôd-rōʾsh ballĕʾummîm</em>, "a wagging of heads among the peoples") — the body-language of contempt: the head-wagging that signals disdain or pitying dismissal (Jer 18:16; Lam 2:15).</p>',
    "15": '<p><strong>כָּל-הַיּוֹם כְּלִמָּתִי נֶגְדִּי</strong> (<em>kol-hayyôm kĕlimmātî negdî</em>, "All day long my disgrace is before me") — <em>kĕlimmāh</em>: disgrace, shame — related to <em>kālam</em> (to be disgraced, v9). <strong>וּבֹשֶׁת פָּנַי כִּסָּתְנִי</strong> (<em>ûbōshet pānay kissātĕnî</em>, "and shame has covered my face") — <em>bōshet</em>: shame; <em>kāsāh</em>: to cover (the same verb as the "covered sin" of Ps 32:1, but now shame rather than sin is what covers). The face as the site of honor/shame — covered with shame rather than shining with the divine face-light.</p>',
    "16": '<p><strong>מִקּוֹל מְחָרֵף וּמְגַדֵּף</strong> (<em>miqqôl mĕḥārêp ûmĕgaddêp</em>, "On account of the taunting voice of the one who reviles and blasphemes") — <em>ḥārap</em> (piel: to taunt, to revile); <em>gādap</em> (piel: to blaspheme, to revile — particularly of speaking against God). The voices of the enemies who simultaneously mock the people and blaspheme God. <strong>מִפְּנֵי אוֹיֵב וּמִתְנַקֵּם</strong> (<em>mippĕnê ʾôyêb ûmitnakkêm</em>, "because of the enemy who seeks revenge") — <em>nāqam</em> (hithpael: to avenge oneself, to seek revenge): the vindictive purpose behind the attack.</p>',
    "17": '<p><strong>כָּל-זֹאת בָּאַתְנוּ וְלֹא שְׁכַחֲנוּךָ</strong> (<em>kol-zōʾt bāʾatnû wĕlōʾ shĕkaḥănûkā</em>, "All this has come upon us, yet we have not forgotten you") — the central theological claim of the psalm: the suffering is not the result of covenant infidelity (contrast Deut 28 where disaster follows apostasy). <em>Shākaḥ</em>: to forget — the covenant violation of forgetting God. The community denies this. <strong>וְלֹא-שִׁקַּרְנוּ בִּבְרִיתֶךָ</strong> (<em>wĕlōʾ-shiqarnû bibrîtekā</em>, "and we have not been unfaithful to your covenant") — <em>shāqar</em>: to be false, to deal falsely, to lie — the covenant (the <em>bĕrît</em>) not violated. This is the psalm of innocent suffering — the lament that cannot explain its pain by appeal to guilt.</p>',
    "18": '<p><strong>לֹא-נָסוֹג אָחוֹר לִבֵּנוּ</strong> (<em>lōʾ-nāsôg ʾāḥôr libbênû</em>, "Our heart has not turned away") — <em>nāsag</em>: to turn back, to retreat (the same verb as "retreat" in v10, now applied to the heart rather than the army — the inward loyalty contrasted with the external military defeat). <strong>וַתֵּט אֲשֻׁרֵינוּ מִנִּי-אָרְחֶךָ</strong> (<em>wattêṭ ʾăshurênû minnî-ʾārĕḥekā</em>, "and our steps have not strayed from your path") — <em>nāṭāh</em>: to deviate, to turn aside. The path (<em>ʾōraḥ</em>) as the way of covenantal life — not abandoned.</p>',
    "19": '<p><strong>כִּי דִכִּיתָנוּ בִּמְקוֹם תַּנִּים</strong> (<em>kî dikkîtānû bimqôm tannîm</em>, "Yet you have crushed us in the haunt of jackals") — <em>dākāh</em> (piel: to crush, to shatter — as the bones are crushed). <em>Tannîm</em>: jackals or sea-monsters (the same word appears as both — here contextually the jackals of the wilderness, the animals that inhabit desolate, destroyed places). <strong>וַתְּכַס עָלֵינוּ בְּצַלְמָוֶת</strong> (<em>wattĕkas ʿālênû bĕṣalmāwet</em>, "and covered us with the shadow of death") — <em>ṣalmāwet</em>: deep darkness, shadow of death (Ps 23:4 — the valley of <em>ṣalmāwet</em>). The total encirclement by lethal darkness.</p>',
    "20": '<p><strong>אִם-שָׁכַחְנוּ שֵׁם אֱלֹהֵינוּ</strong> (<em>ʾim-shākaḥnû shêm ʾĕlōhênû</em>, "If we had forgotten the name of our God") — the conditional self-examination: "if we had done X..." — the <em>ʾim</em> (if) is an oath-structure in Hebrew: "if we had forgotten… [then let the punishment stand, but we haven\'t]." <strong>וַנִּפְרֹשׂ כַּפֵּינוּ לְאֵל זָר</strong> (<em>wanniprōś kappênû lĕʾêl zār</em>, "or spread our hands in prayer toward a foreign god") — <em>pāraś kappayim</em>: to spread/extend the palms in prayer (the upward gesture of supplication). <em>ʾÊl zār</em>: a strange/foreign god.</p>',
    "21": '<p><strong>הֲלֹא אֱלֹהִים יַחֲקָר-זֹאת</strong> (<em>hălōʾ ʾĕlōhîm yaḥăqār-zōʾt</em>, "Would God not discover this?") — <em>ḥāqar</em>: to search out, to examine thoroughly — the divine forensic examination that reveals everything hidden. <strong>כִּי-הוּא יֹדֵעַ תַּעֲלֻמוֹת לֵב</strong> (<em>kî-hûʾ yōdêaʿ taʿălumôt lêb</em>, "For he knows the hidden things of the heart") — <em>taʿălumôt</em>: hidden things, secrets (from <em>ʿālam</em>: to conceal). God knows what is concealed even from human self-examination — the argument is: if we had sinned in secret, God would know. The fact of suffering does not imply the fact of hidden sin.</p>',
    "22": '<p><strong>כִּי-עָלֶיךָ הֹרַגְנוּ כָל-הַיּוֹם</strong> (<em>kî-ʿālêkā hōragnû kol-hayyôm</em>, "Yet for your sake we face death all day long") — the key theological claim: the suffering is "for your sake" (<em>ʿālêkā</em>) — not because of unfaithfulness but because of faithfulness. <strong>נֶחְשַׁבְנוּ כְּצֹאן טִבְחָה</strong> (<em>neḥshābnû kĕṣōʾn ṭibḥāh</em>, "we are counted as sheep destined for slaughter") — <em>ḥāshab</em>: to be reckoned, to be counted (the accounting root of Ps 32:2) — reckoned as slaughter-sheep. Paul quotes this verse verbatim in Romans 8:36 to describe the condition of believers facing persecution, then immediately follows with: "No, in all these things we are more than conquerors through him who loved us." The psalm\'s suffering-for-faithfulness becomes the NT\'s theology of cross-bearing discipleship.</p>',
    "23": '<p><strong>עוּרָה לָמָּה תִישַׁן אֲדֹנָי</strong> (<em>ʿûrāh lāmmāh tîshān ʾădōnāy</em>, "Wake up! Why are you sleeping, O Lord?") — <em>ʿûr</em> (qal imperative: to awake, to rouse oneself). The remarkable anthropomorphism: the LORD asleep — not a theological claim that God sleeps (Ps 121:4 explicitly denies this: "He who watches over Israel will neither slumber nor sleep") but the experiential language of a community in extremis. The prayer uses the only vocabulary available to describe the feeling of divine inaction. <strong>הָקִיצָה אַל-תִּזְנַח לָנֶצַח</strong> (<em>hāqîṣāh ʾal-tiznaḥ lāneṣaḥ</em>, "Rise up! Do not reject us forever!") — <em>qîṣ</em>: to awake; <em>zānaḥ</em>: to reject (as in v9). The fear that the rejection might be permanent (<em>lāneṣaḥ</em>: forever).</p>',
    "24": '<p><strong>לָמָּה-פָנֶיךָ תַסְתִּיר</strong> (<em>lāmmāh-pānêkā tastîr</em>, "Why do you hide your face?") — <em>hester pānim</em> (hiding of the face — as in Ps 30:7; 31:17): the divine concealment experienced as absence. <strong>תִּשְׁכַּח עָנְיֵנוּ וְלַחֲצֵנוּ</strong> (<em>tishkaḥ ʿānyênû wĕlaḥăṣênû</em>, "Why do you ignore our affliction and our oppression?") — <em>ʿonyī</em>: affliction, poverty, humiliation (from <em>ʿānāh</em>: to be bent/bowed down); <em>laḥas</em>: oppression (as in Ps 42:9). Both words describe the crushing of a people under superior force.</p>',
    "25": '<p><strong>כִּי שָׁחָה לֶעָפָר נַפְשֵׁנוּ</strong> (<em>kî shāḥāh leʿāpār napshênû</em>, "For our soul is brought down to the dust") — <em>shāḥāh</em>: to bow, to sink down (the same root as <em>tishtôḥăḥî</em> in Ps 42:5 — the downcast soul); <em>ʿāpār</em>: dust (as in Ps 30:9 — the dust of death). <strong>דָּבְקָה לָאָרֶץ בִּטְנֵנוּ</strong> (<em>dābĕqāh lāʾāreṣ biṭnênû</em>, "our body clings to the ground") — <em>dābaq</em>: to cling, to stick fast — the intimate bodily contact with the ground in utter prostration.</p>',
    "26": '<p><strong>קוּמָה עֶזְרָתָה לָּנוּ</strong> (<em>qûmāh ʿezrātāh llānû</em>, "Rise up and help us!") — <em>qûm</em> (imperative: rise!) — the same imperative used for divine waking in v23 but now with the purpose of help (<em>ʿezer</em>). <strong>וּפְדֵנוּ לְמַעַן חַסְדֶּךָ</strong> (<em>ûpĕdênû lĕmaʿan ḥasdekā</em>, "Deliver us for the sake of your steadfast love") — <em>pādāh</em>: to redeem, to ransom (as in Ps 31:5). <em>Lĕmaʿan ḥasdekā</em>: "for the sake of your covenant-loyalty" — the final appeal grounds the prayer not in the community\'s merit (which has been affirmed) but in God\'s own covenant character. The psalm ends not with self-justification but with appeal to divine <em>ḥesed</em>.</p>',
  },
  "45": {
    "1": '<p><strong>רָחַשׁ לִבִּי דָּבָר טוֹב</strong> (<em>rāḥash libbî dābār ṭôb</em>, "My heart is overflowing with a beautiful theme") — <em>rāḥash</em>: a hapax legomenon (appears only here) — to bubble up, to overflow, to boil over (like a pot). The heart as the vessel from which the beautiful word pours. <strong>אֹמֵר אָנִי מַעֲשַׂי לְמֶלֶךְ</strong> (<em>ʾōmêr ʾānî maʿăśay lĕmelek</em>, "I address my poem to the king") — a wedding ode for the king; <em>maʿăśay</em>: my work(s), my compositions. <strong>לְשׁוֹנִי עֵט סֹפֵר מָהִיר</strong> (<em>lĕshônî ʿêṭ sōpêr māhîr</em>, "my tongue is the pen of a skilled scribe") — the tongue as a writing instrument, the poet as a skilled copyist (<em>māhîr</em>: swift, expert). The superscription: "A Song of Loves" (<em>shîr yĕdîdōt</em>) — <em>yĕdîdāh</em>: beloved, darling (the same root as <em>yĕdîdîm</em>, the covenant love-name).</p>',
    "2": '<p><strong>יָפְיָפִיתָ מִבְּנֵי אָדָם</strong> (<em>yāpyāpîtā mibbĕnê ʾādām</em>, "You are more handsome than any other man") — <em>yāpāh</em> (doubled for intensity): the most beautiful among Adam\'s sons. <strong>הוּצַק חֵן בְּשִׂפְתוֹתֶיךָ</strong> (<em>hûṣaq ḥên bĕśiptôtêkā</em>, "grace is poured into your lips") — <em>yāṣaq</em> (hophal: to be poured out): grace (<em>ḥên</em>) as liquid poured into the king\'s speech. <strong>עַל-כֵּן בֵּרַכְךָ אֱלֹהִים לְעוֹלָם</strong> (<em>ʿal-kên bêrakĕkā ʾĕlōhîm lĕʿôlām</em>, "therefore God has blessed you forever") — the beauty and gracious speech are not independent gifts but expressions of the divine blessing of the anointed king.</p>',
    "3": '<p><strong>חֲגוֹר-חַרְבְּךָ עַל-יָרֵךְ גִּבּוֹר</strong> (<em>ḥăgôr-ḥarbĕkā ʿal-yārêk gibbôr</em>, "Strap your sword on your thigh, O champion") — <em>ḥāgar</em>: to gird, to belt; <em>gibbôr</em>: the mighty warrior-hero. <strong>הוֹדְךָ וַהֲדָרֶךָ</strong> (<em>hôdĕkā wahădārekā</em>, "your glory and splendor") — <em>hôd</em> and <em>hādār</em>: the divine glory-vocabulary of Ps 21:5, now applied to the warrior-king. The warrior\'s military accoutrements are described in the language of divine splendor — the king as the earthly bearer of divine glory.</p>',
    "4": '<p><strong>וַהֲדָרְךָ צְלַח רְכַב</strong> (<em>wahădārkā ṣĕlaḥ rĕkab</em>, "Ride out victoriously in your splendor") — <em>ṣālaḥ</em>: to prosper, to succeed (the cavalry image). <strong>עַל-דְּבַר-אֱמֶת וְעַנְוָה-צֶדֶק</strong> (<em>ʿal-dĕbar-ʾĕmet wĕʿanwāh-ṣedeq</em>, "for the sake of truth, humility, and righteousness") — the three foundations of the ideal kingship: <em>ʾĕmet</em> (truth/faithfulness), <em>ʿanwāh</em> (meekness/humility — the same word used of Moses in Num 12:3 and of the meek who inherit the earth in Matt 5:5), and <em>ṣedeq</em> (righteousness). <strong>וְתוֹרְךָ נוֹרָאוֹת יְמִינֶךָ</strong> (<em>wĕtôrĕkā nôrāʾôt yĕmînekā</em>, "let your right hand achieve awesome deeds") — <em>yārah</em> (hiphil: to teach/direct — but here the sense is "to show, to point out"): the right hand teaching awesome things through the deeds of war.</p>',
    "5": '<p><strong>חִצֶּיךָ שְׁנוּנִים עַמִּים תַּחְתֶּיךָ יִפְּלוּ</strong> (<em>ḥiṣṣêkā shĕnûnîm ʿammîm taḥtêkā yippĕlû</em>, "Your arrows are sharp, bringing peoples down beneath you") — <em>shānān</em>: to sharpen (the whetted arrows of the divine warrior, now the king\'s arrows). <em>Yippĕlû taḥtêkā</em>: "they fall beneath you" — the posture of the defeated before the victor (Ps 18:38-39). <strong>בְּלֵב אוֹיְבֵי הַמֶּלֶךְ</strong> (<em>bĕlêb ʾôyĕbê hammelek</em>, "they pierce into the hearts of the king\'s enemies") — the arrows strike to the heart, not merely the body\'s surface.</p>',
    "6": '<p><strong>כִּסְאֲךָ אֱלֹהִים עוֹלָם וָעֶד</strong> (<em>kisʾăkā ʾĕlōhîm ʿôlām wāʿed</em>, "Your throne, O God, is forever and ever") — one of the most theologically contested verses in the OT. The king is addressed as <em>ʾĕlōhîm</em> (God). Three main readings: (1) "Your throne is God\'s throne forever" — the <em>ʾĕlōhîm</em> as a genitive of possession; (2) "God is your throne forever" — <em>ʾĕlōhîm</em> as predicate; (3) the Psalmist directly addresses the king as <em>ʾĕlōhîm</em> — applying divine language to the anointed representative. The LXX reads it as direct address: <em>ὁ θρόνος σου ὁ θεός</em> ("your throne, O God"). Hebrews 1:8 quotes this verse and applies it to Christ: "But about the Son he says, \'Your throne, O God, will last for ever and ever.\'<em></em>" The NT\'s authoritative interpretation establishes this as Messianic — the eternal throne of the Son, not merely of a historical Davidic king. <strong>שֵׁבֶט מִישֹׁר שֵׁבֶט מַלְכוּתֶךָ</strong> (<em>shêbeṭ mîshōr shêbeṭ malkûtekā</em>, "the scepter of your kingdom is a righteous scepter") — <em>shêbeṭ</em>: the royal scepter (the symbol of authority and judgment); <em>mîshōr</em>: uprightness, justice (the level/straight as the standard of just governance).</p>',
    "7": '<p><strong>אָהַבְתָּ צֶּדֶק וַתִּשְׂנָא רֶשַׁע</strong> (<em>ʾāhabtā ṣedeq wattishnāʾ reshaʿ</em>, "You have loved righteousness and hated wickedness") — the moral character of the anointed king: active love for <em>ṣedeq</em> (righteousness/justice) and active hatred for <em>reshaʿ</em> (wickedness). The pairing: love and hate as the two poles of moral commitment. <strong>עַל-כֵּן מְשָׁחֲךָ אֱלֹהִים אֱלֹהֶיךָ שֶׁמֶן שָׂשׂוֹן מֵחֲבֵרֶיךָ</strong> (<em>ʿal-kên mĕshāḥăkā ʾĕlōhîm ʾĕlōhêkā shemen śāśôn mêḥăbêrêkā</em>, "therefore God, your God, has anointed you with the oil of gladness beyond all your companions") — <em>māshaḥ</em>: to anoint (the verb behind <em>māshîaḥ/Messiah</em>); <em>shemen śāśôn</em>: "oil of gladness/exultation." The anointing with joy-oil beyond all others. Hebrews 1:9 quotes this verse of Christ as the uniquely anointed one whose joy-anointing exceeds all others.</p>',
    "8": '<p><strong>מֹר-וַאֲהָלוֹת קְצִיעוֹת כָּל-בִּגְדֹתֶיךָ</strong> (<em>mōr-waʾăhālôt qĕṣîʿôt kol-bigdōtêkā</em>, "All your robes are fragrant with myrrh, aloes, and cassia") — <em>mōr</em>: myrrh (the prized resin used in the anointing oil, Exod 30:23); <em>ʾăhālôt</em>: aloes (a fragrant wood); <em>qĕṣîʿāh</em>: cassia (cinnamon-like spice). The three spices of the anointing oil and the divine presence concentrated in the royal garments. <strong>מִן-הֵיכְלֵי שֵׁן</strong> (<em>min-hêkĕlê shên</em>, "from ivory palaces") — <em>shên</em>: ivory (the luxury material of the royal palace, as in Ahab\'s ivory house, 1 Kgs 22:39). Music (<em>minnî</em>) bringing joy from within the palace of ivory.</p>',
    "9": '<p><strong>בְּנוֹת מְלָכִים בְּיִקְּרוֹתֶיךָ</strong> (<em>bĕnôt mĕlākîm bĕyiqqĕrôtêkā</em>, "Daughters of kings are among your ladies of honor") — the international scope of the royal court. <strong>נִצְּבָה שֵׁגַל לִימִינְךָ בְּכֶתֶם אוֹפִיר</strong> (<em>niṣṣĕbāh shêgal lîmînĕkā bĕketem ʾôpîr</em>, "at your right hand stands the queen arrayed in gold of Ophir") — <em>shêgal</em>: the queen/consort; <em>ketem ʾôpîr</em>: Ophir-gold — the finest gold of the ancient world (1 Kgs 9:28; Job 28:16). Positioned at the king\'s right hand — the place of honor.</p>',
    "10": '<p><strong>שִׁמְעִי-בַת וּרְאִי וְהַטִּי אָזְנֵךְ</strong> (<em>shîmʿî-bat ûrĕʾî wĕhaṭṭî ʾāznêk</em>, "Listen, daughter, and pay attention; lean in with your ear") — the address turns to the bride: "Listen, daughter" — <em>bat</em> used as a term of address for the queen. The three imperatives of attentive reception: hear, see, incline the ear. <strong>וְשִׁכְחִי עַמֵּךְ וּבֵית אָבִיךְ</strong> (<em>wĕshikhĕhî ʿammêk ûbêt ʾābîk</em>, "forget your own people and your father\'s house") — the call to transfer primary loyalty from birth-family to the new royal household — the same structure as the Davidic covenant\'s call to leave the old identity.</p>',
    "11": '<p><strong>וְיִתְאָו הַמֶּלֶךְ יָפְיֵךְ</strong> (<em>wĕyitʾāw hammelek yāpyêk</em>, "Then the king will desire your beauty") — <em>ʾāwāh</em> (hithpael: to long for, to desire): the king\'s desire for the bride who has transferred her loyalty. <strong>כִּי-הוּא אֲדֹנַיִךְ וְהִשְׁתַּחֲוִי-לוֹ</strong> (<em>kî-hûʾ ʾădōnayik wĕhishtaḥăwî-lô</em>, "because he is your lord, bow down to him") — the structural hierarchy: the bride\'s lord (<em>ʾādôn</em>) whom she acknowledges through the act of prostration.</p>',
    "12": '<p><strong>וּבַת-צֹר בְּמִנְחָה פָנַיִךְ יְחַלּוּ</strong> (<em>ûbat-ṣōr bĕminḥāh pānayik yĕḥallû</em>, "The daughter of Tyre comes bearing a gift") — <em>bat-ṣōr</em>: "daughter of Tyre" — a representative of the wealthy trading nations coming as a suppliant. <em>Pānayik yĕḥallû</em>: "they will seek your favor" (literally "make your face gracious") — the international acknowledgment of the queen\'s standing. The nations bringing tribute to the royal court, as in Ps 72:10-11.</p>',
    "13": '<p><strong>כָּל-כְּבוּדָּה בַת-מֶלֶךְ פְּנִימָה</strong> (<em>kol-kĕbûddāh bat-melek pĕnîmāh</em>, "The king\'s daughter is altogether beautiful within") — <em>kābôd</em>: weight, honor, beauty (the divine glory-word applied to the inner beauty of the royal bride). <em>Pĕnîmāh</em>: inwardly, within — the beauty is interior, the <em>kābôd</em> is found in the inner person. <strong>מִמִּשְׁבְּצוֹת זָהָב לְבוּשָׁהּ</strong> (<em>mimmishbĕṣôt zāhāb lĕbûshāh</em>, "her garment is interwoven with gold") — <em>mishbĕṣôt</em>: settings, inlaid work (from <em>shābaṣ</em>: to interweave, to set in gold). The outer garment as the visible expression of the inner beauty.</p>',
    "14": '<p><strong>לִרְקָמוֹת תּוּבַל לַמֶּלֶךְ</strong> (<em>lirqāmôt tûbal lammelek</em>, "In embroidered garments she will be led to the king") — <em>riqmāh</em>: embroidery, variegated work (the multi-colored woven garment as a sign of status — Joseph\'s coat, Gen 37:3, uses the same root). <strong>בְּתוּלוֹת אַחֲרֶיהָ רֵעוֹתֶיהָ</strong> (<em>bĕtûlôt ʾaḥărêhā rêʿôtêhā</em>, "the maidens, her companions, will follow her") — <em>bĕtûlôt</em>: virgins, unmarried women. The bridal procession.</p>',
    "15": '<p><strong>תּוּבַלְנָה בִּשְׂמָחֹת וָגִיל</strong> (<em>tûbalĕnāh biśmāḥōt wāgîl</em>, "With joy and celebration they will be led in") — <em>śimḥāh</em> and <em>gîl</em>: the twin joy-words (as in Ps 21:1; 31:7). The bridal procession characterized by the full vocabulary of rejoicing. <strong>יְבֹאֵינָה בְּהֵיכַל מֶלֶךְ</strong> (<em>yĕbōʾênāh bĕhêkal melek</em>, "they will enter the king\'s palace") — <em>hêkāl</em>: palace or temple (the same word for both — the ambiguity is deliberate in the royal psalm where the king\'s palace and the divine dwelling are conceptually linked).</p>',
    "16": '<p><strong>תַּחַת אֲבֹתֶיךָ יִהְיוּ בָנֶיךָ</strong> (<em>taḥat ʾăbōtêkā yihyû bānêkā</em>, "In place of your ancestors will be your sons") — the dynastic continuity: the sons who will replace the fathers in the royal line. <strong>תְּשִׁיתֵמוֹ לְשָׂרִים בְּכָל-הָאָרֶץ</strong> (<em>tĕshîtêmô lĕśārîm bĕkol-hāʾāreṣ</em>, "you will appoint them as princes throughout all the earth") — <em>śār</em>: prince, official, ruler (from the same root as <em>śārāh</em>: to have power). The Davidic dynasty projected onto the whole earth — a universal Messianic horizon.</p>',
    "17": '<p><strong>אַזְכִּירָה שִׁמְךָ בְּכָל-דֹּר וָדֹר</strong> (<em>ʾazkîrāh shimkā bĕkol-dōr wādōr</em>, "I will cause your name to be remembered in all generations") — the Psalmist-poet\'s vow: to perpetuate the king\'s <em>shêm</em> (name/reputation) through the generations by means of this very poem. <strong>עַל-כֵּן עַמִּים יְהוֹדוּךָ לְעֹלָם וָעֶד</strong> (<em>ʿal-kên ʿammîm yĕhôdûkā lĕʿōlām wāʿed</em>, "therefore the peoples will praise you forever and ever") — the universal praise (<em>ʿammîm</em>: peoples, nations) as the eschatological horizon: the king whose name is perpetuated in every generation will be praised by all nations forever. The poem itself is the vehicle of eternal remembrance — and the NT\'s Messianic reading of Ps 45 is exactly this perpetuation.</p>',
  },
  "46": {
    "1": '<p><strong>אֱלֹהִים לָנוּ מַחֲסֶה וָעֹז</strong> (<em>ʾĕlōhîm lānû maḥăseh wāʿōz</em>, "God is our refuge and strength") — <em>maḥăseh</em>: refuge, shelter (from <em>ḥāsāh</em>: to take refuge — the recurring trust-verb of the Psalter). <em>ʿŌz</em>: strength, might (as in Ps 28:7-8; 29:1). The pairing: both shelter and strength — protection from outside threat and capacity within. <strong>עֶזְרָה בְצָרוֹת נִמְצָא מְאֹד</strong> (<em>ʿezrāh bĕṣārôt nimṣāʾ mĕʾōd</em>, "a help that is always present in times of trouble") — <em>nimṣāʾ</em> (niphal: to be found, to be available): help that is actively findable (<em>mĕʾōd</em>: very much, exceedingly) in the tight-place (<em>ṣārôt</em>: troubles, as in <em>ṣar</em>).</p>',
    "2": '<p><strong>עַל-כֵּן לֹא-נִירָא בְּהָמִיר אָרֶץ</strong> (<em>ʿal-kên lōʾ-nîrāʾ bĕhāmîr ʾāreṣ</em>, "Therefore we will not fear, even if the earth gives way") — <em>hāmar</em>: to be changed, to be exchanged, to give way (the earth itself undergoing total transformation). <strong>וּבְמוֹט הָרִים בְּלֵב יַמִּים</strong> (<em>ûbĕmôṭ hārîm bĕlêb yammîm</em>, "even if the mountains topple into the heart of the sea") — <em>māṭ</em>: to totter, to slip (Ps 30:6; 32:6 — the verb of being shaken). The mountains falling into the sea is the image of ultimate cosmic catastrophe — the end of the stable world order. The confession: even then, no fear.</p>',
    "3": '<p><strong>יֶהֱמוּ יֶחְמְרוּ מֵימָיו</strong> (<em>yehĕmû yeḥmĕrû mêmāyw</em>, "Though the waters roar and churn") — <em>hāmāh</em>: to roar, to be turbulent (the inner noise of Ps 42:5, now applied to the chaotic waters); <em>ḥāmar</em>: to foam, to ferment, to churn. <strong>יִרְעֲשׁוּ הָרִים בְּגַאֲוָתוֹ סֶלָה</strong> (<em>yirʿăshû hārîm bĕgaʾăwātô selāh</em>, "though the mountains quake at the surging sea") — <em>rāʿash</em>: to shake, to tremble (the earthquake-trembling of Ps 18:7); <em>gaʾăwāh</em>: the pride/swelling surge of the sea. <em>Selāh</em> — pause in the face of cosmic chaos.</p>',
    "4": '<p><strong>נָהָר פְּלָגָיו יְשַׂמְּחוּ עִיר-אֱלֹהִים</strong> (<em>nāhār pĕlāgāyw yĕśammĕḥû ʿîr-ʾĕlōhîm</em>, "There is a river whose streams bring joy to the city of God") — <em>nāhār</em>: a river; <em>pĕlāgîm</em>: its streams, channels (as in Ps 1:3 — <em>palgê māyim</em>). The rivers of chaos (v3) contrast with the life-giving river of God\'s city. Jerusalem had no natural river — the image is the heavenly river of Eden (Gen 2:10) or the eschatological river of Ezek 47:1-12 and Rev 22:1-2. <strong>קְדֹשׁ מִשְׁכְּנֵי עֶלְיוֹן</strong> (<em>qĕdōsh mishkĕnê ʿelyôn</em>, "the sacred dwelling of the Most High") — the divine dwelling (the Tabernacle / temple) as the holy place of <em>ʿElyôn</em> (the Most High — the highest divine title).</p>',
    "5": '<p><strong>אֱלֹהִים בְּקִרְבָּהּ בַּל-תִּמּוֹט</strong> (<em>ʾĕlōhîm bĕqirbāh bal-timmôṭ</em>, "God is within her; she will not be shaken") — <em>qereb</em>: midst, interior — God in the innermost part of the city. <em>Māṭ</em> (niphal: to be shaken, to totter): the word for instability used repeatedly in this psalm cluster — the city will not be made to totter. <strong>יַעְזְרֶהָ אֱלֹהִים לִפְנוֹת בֹּקֶר</strong> (<em>yaʿzĕrehā ʾĕlōhîm lipnôt bōqer</em>, "God will help her when morning breaks") — <em>lipnôt bōqer</em>: "at the turning of the morning" — the decisive moment when the morning breaks and the night-siege ends. Morning as the time of divine intervention (Ps 30:5; 46:5 — the rescue comes with dawn).</p>',
    "6": '<p><strong>הָמוּ גוֹיִם מָטוּ מַמְלָכוֹת</strong> (<em>hāmû gôyim māṭû mamlākôt</em>, "Nations raged and kingdoms shook") — <em>hāmāh</em> (the same roaring as the waters in v3): the nations\' tumult mirrors the cosmic chaos. <em>Māṭ</em> (to totter/shake) applied to kingdoms — the unstable nations are the political equivalent of the unstable mountains. <strong>נָתַן בְּקוֹלוֹ תָּמוּג אָרֶץ</strong> (<em>nātan bĕqôlô tāmûg ʾāreṣ</em>, "he lifted his voice, and the earth dissolved") — the divine voice (as in Ps 29:3-9 — the qôl YHWH) dissolving the earth. <em>Māwag</em>: to melt, to dissolve — the paradox: the earth that cannot be shaken (v2-5) because God is within it can be dissolved by his voice when he acts against the hostile nations.</p>',
    "7": '<p><strong>יְהוָה צְבָאוֹת עִמָּנוּ</strong> (<em>YHWH ṣĕbāʾôt ʿimmānû</em>, "The LORD of hosts is with us") — the refrain (also v11). <em>YHWH ṣĕbāʾôt</em>: the LORD of Armies/Hosts — the covenant name combined with the military title. <em>ʿImmānû</em>: "with us" — the same two Hebrew components as <em>ʿImmānûʾêl</em> (Immanuel: God-with-us, Isa 7:14 / Matt 1:23). The Immanuel promise is embedded in this refrain: the divine warrior whose name is Armies is with us. <strong>מִשְׂגָּב-לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה</strong> (<em>miśgāb-lānû ʾĕlōhê yaʿăqōb selāh</em>, "the God of Jacob is our fortress") — <em>miśgāb</em>: high fortress, elevated stronghold (as in Ps 18:2; 59:9). The God of Jacob — the patriarchal covenant-name — is the elevated stronghold of the community.</p>',
    "8": '<p><strong>לְכוּ-חֲזוּ מִפְעֲלוֹת יְהוָה</strong> (<em>lĕkû-ḥăzû mipʿălôt YHWH</em>, "Come and see what the LORD has done") — <em>ḥāzāh</em>: to gaze, to behold (the prophetic vision-word — used for the seeing of visions, Isa 1:1). <em>Mipʿălôt YHWH</em>: the works/deeds of the LORD (the same root <em>pāʿal</em> as in Ps 28:4-5). <strong>אֲשֶׁר-שָׂם שַׁמּוֹת בָּאָרֶץ</strong> (<em>ʾăsher-śām shammôt bāʾāreṣ</em>, "what desolations he has brought upon the earth") — <em>shammāh</em>: desolation, devastation — the destruction the LORD has wrought among the nations who attacked his city.</p>',
    "9": '<p><strong>מַשְׁבִּית מִלְחָמוֹת עַד-קְצֵה הָאָרֶץ</strong> (<em>mashbît milḥāmôt ʿad-qĕṣeh hāʾāreṣ</em>, "He puts an end to wars across the whole earth") — <em>shābat</em> (hiphil: to cause to cease, to make stop — the same root as Sabbath/<em>shabbāt</em>): God making wars cease as he makes labor cease on the seventh day. The eschatological Sabbath of warfare. <strong>קֶשֶׁת יְשַׁבֵּר</strong> (<em>qeshet yĕshabbêr</em>, "he breaks bows") — <em>shābar</em>: to break, to shatter (as he shattered the cedars in Ps 29:5 — the same divine shattering of military power). The war-implements (bows, spears, war-chariots) destroyed.</p>',
    "10": '<p><strong>הַרְפּוּ וּדְעוּ כִּי-אָנֹכִי אֱלֹהִים</strong> (<em>harpû ûdĕʿû kî-ʾānōkî ʾĕlōhîm</em>, "Be still, and know that I am God") — <em>rāpāh</em> (hiphil imperative: to let drop, to relax, to release the grip — not merely "be quiet" but actively letting go): the command to release the striving, to unclench. The English "be still" captures the resulting posture but misses the active release: "Let go and know." <em>Dĕʿû</em>: to know — not merely intellectual assent but the experiential, covenantal knowing. <strong>אָרוּם בַּגּוֹיִם אָרוּם בָּאָרֶץ</strong> (<em>ārûm baggôyim ārûm bāʾāreṣ</em>, "I will be exalted among the nations; I will be exalted throughout the earth") — <em>rûm</em>: to be high, to be exalted. The double exaltation — among the hostile nations and throughout the entire earth — is the eschatological goal of all the divine acts of vv8-9.</p>',
    "11": '<p>The refrain for the second time: <strong>יְהוָה צְבָאוֹת עִמָּנוּ מִשְׂגָּב-לָנוּ אֱלֹהֵי יַעֲקֹב</strong> — "The LORD of hosts is with us; the God of Jacob is our fortress." The repetition of the refrain encloses the declaration of the LORD\'s deeds (vv8-10) in the same covenantal affirmation: before and after the description of what God does (shattering warfare, commanding rest), the community confesses who God is: the LORD of armies, with us, the God of Jacob, our high fortress. The Immanuel-name (<em>ʿimmānû</em>) brackets the central theology of the psalm.</p>',
  },
  "47": {
    "1": '<p><strong>כָּל-הָעַמִּים תִּקְעוּ-כָף</strong> (<em>kol-hāʿammîm tiqĕʿû-kāp</em>, "Clap your hands, all you peoples") — the universal summons: not Israel alone but <em>kol-hāʿammîm</em> (all the peoples/nations — the full breadth of humanity). <em>Tāqaʿ kap</em>: to strike the palm (clapping as the physical expression of acclamation — used at the coronation of kings, 2 Kgs 11:12). <strong>הָרִיעוּ לֵאלֹהִים בְּקוֹל רִנָּה</strong> (<em>hārîʿû lêʾlōhîm bĕqôl rinnāh</em>, "shout to God with a voice of joy") — <em>rûaʿ</em>: to shout, to raise the war-cry/victory shout (the <em>tĕrûʿāh</em> of battle and celebration). <em>Rinnāh</em>: the ringing joy-cry.</p>',
    "2": '<p><strong>כִּי-יְהוָה עֶלְיוֹן נוֹרָא</strong> (<em>kî-YHWH ʿelyôn nôrāʾ</em>, "For the LORD Most High is to be feared") — <em>ʿElyôn</em>: the Most High (the highest divine title, combining the covenantal name YHWH with the superlative divine appellative). <em>Nôrāʾ</em>: awesome, fearsome (from <em>yārēʾ</em>: to fear) — the cause of holy fear. <strong>מֶלֶךְ גָּדוֹל עַל-כָּל-הָאָרֶץ</strong> (<em>melek gādôl ʿal-kol-hāʾāreṣ</em>, "he is a great King over the whole earth") — <em>melek gādôl</em>: the great king — the suzerain title used in Assyrian royal inscriptions. The psalm appropriates the language of ancient Near Eastern imperial lordship and applies it to YHWH over all the earth.</p>',
    "3": '<p><strong>יַדְבֵּר עַמִּים תַּחְתֵּינוּ</strong> (<em>yadĕbbêr ʿammîm taḥtênû</em>, "He subdues peoples under us") — <em>dābar</em> (piel: to subdue, to bring into subjection — a rare piel usage). <strong>וּלְאֻמִּים תַּחַת רַגְלֵינוּ</strong> (<em>ûlĕʾummîm taḥat raglênû</em>, "and nations beneath our feet") — "under the feet" as the posture of the conquered (Ps 18:38-39; Josh 10:24). The nations placed beneath Israel by divine action.</p>',
    "4": '<p><strong>יִבְחַר-לָנוּ אֶת-נַחֲלָתֵנוּ</strong> (<em>yibḥar-lānû ʾet-naḥălātênû</em>, "He chose our inheritance for us") — <em>bāḥar</em>: to choose (the election vocabulary of Deut 7:6 — as in Ps 33:12). <em>Naḥălāh</em>: inheritance, portion (the land as the covenantal inheritance). <strong>אֶת גְּאוֹן יַעֲקֹב אֲשֶׁר-אָהֵב</strong> (<em>ʾet gĕʾôn yaʿăqōb ʾăsher-ʾāhêb</em>, "the glory of Jacob whom he loved") — <em>gĕʾôn yaʿăqōb</em>: the "pride/majesty of Jacob" — the land or the people as the subject of divine love. <em>Selāh</em>.</p>',
    "5": '<p><strong>עָלָה אֱלֹהִים בִּתְרוּעָה</strong> (<em>ʿālāh ʾĕlōhîm bitĕrûʿāh</em>, "God has ascended with shouts of joy") — <em>ʿālāh</em>: to go up, to ascend. The divine ascent — possibly the ascent of the Ark to Jerusalem (2 Sam 6), or the ascent of YHWH to his heavenly throne after the victory. <em>Bitĕrûʿāh</em>: "with the blast/shout" — the joyful military/coronation cry. Paul uses the vocabulary of divine ascent (from Ps 68:18, which shares the context of Ps 47) in Eph 4:8 for Christ\'s ascension. <strong>יְהוָה בְּקוֹל שׁוֹפָר</strong> (<em>YHWH bĕqôl shôpār</em>, "the LORD with the sound of a ram\'s horn") — <em>shôpār</em>: the ram\'s horn trumpet used at coronations, holy days, and divine appearances (Exod 19:13, 16, 19). The ascent announced by the royal trumpet of the divine King.</p>',
    "6": '<p><strong>זַמְּרוּ אֱלֹהִים זַמֵּרוּ</strong> (<em>zammĕrû ʾĕlōhîm zammêrû</em>, "Sing praises to God, sing praises!") — the intensive repetition: <em>zāmar</em> (to sing with instruments) four times in vv6-7 — more concentrated than anywhere else in the Psalter. <strong>זַמְּרוּ לְמַלְכֵּנוּ זַמֵּרוּ</strong> (<em>zammĕrû lĕmalkênû zammêrû</em>, "Sing praises to our King, sing praises!") — the double ascription: God and King. The four-fold <em>zammĕrû</em> without content specifics — the praise itself without needing to enumerate what is praised.</p>',
    "7": '<p><strong>כִּי מֶלֶךְ כָּל-הָאָרֶץ אֱלֹהִים</strong> (<em>kî melek kol-hāʾāreṣ ʾĕlōhîm</em>, "For God is the King of the whole earth") — the universal kingship declared as the reason for the universal praise. <strong>זַמְּרוּ מַשְׂכִּיל</strong> (<em>zammĕrû maskîl</em>, "sing praises with understanding") — <em>maskîl</em>: with understanding/wisdom (the same word as the psalm-type heading). The praise is not merely emotional or musical but intellectual — understanding what it is that is being praised. Intelligent praise.</p>',
    "8": '<p><strong>מָלַךְ אֱלֹהִים עַל-גּוֹיִם</strong> (<em>mālaḵ ʾĕlōhîm ʿal-gôyim</em>, "God reigns over the nations") — <em>mālaḵ</em>: to reign, to be king. The present reality of divine kingship: not merely that God will reign but that he reigns now over the nations (<em>gôyim</em>) — including those who do not yet acknowledge it. <strong>אֱלֹהִים יָשַׁב עַל-כִּסֵּא קָדְשׁוֹ</strong> (<em>ʾĕlōhîm yāshab ʿal-kissēʾ qodshô</em>, "God is seated on his holy throne") — <em>yāshab</em>: to sit, to be enthroned (as in Ps 29:10: the LORD sat enthroned over the Flood). The holy throne (<em>kissēʾ qodshô</em>) as the seat of universal authority.</p>',
    "9": '<p><strong>נְדִיבֵי עַמִּים נֶאֱסָפוּ</strong> (<em>nĕdîbê ʿammîm neʾĕsāpû</em>, "The nobles of the nations have gathered") — <em>nādîb</em>: the voluntary, freely-giving noble; the generous prince. The willing/voluntary gathering of the nations\' nobility. <strong>עַם אֱלֹהֵי אַבְרָהָם</strong> (<em>ʿam ʾĕlōhê ʾabrāhām</em>, "as the people of the God of Abraham") — the most surprising claim: the nobles of the nations gathered as the people of the God of Abraham — not absorbed into Israel but joining the covenant community as full members. This is the eschatological fulfillment of the Abrahamic promise: "through you all the families of the earth will be blessed" (Gen 12:3). Paul\'s theology of Gentile inclusion (Gal 3:8: "the Scripture foresaw that God would justify the Gentiles by faith") draws on exactly this horizon. <strong>כִּי לֵאלֹהִים מָגִנֵּי-אֶרֶץ מְאֹד נַעֲלָה</strong> (<em>kî lêʾlōhîm māginnê-ʾereṣ mĕʾōd naʿălāh</em>, "for the rulers of the earth belong to God; he is highly exalted") — the ultimate claim of the psalm: all earthly rulers, all shields/protectors of the earth, belong to God — <em>mĕʾōd naʿălāh</em>: "greatly exalted." The final word is the exaltation that began with the ascending God (v5).</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    for ch in range(41, 48):
        print(f'  ch{ch}: {len(existing.get(str(ch), {}))} verses')
    print('Psalms 41-47 mkt-original written.')

if __name__ == '__main__':
    main()
